-- Generated from data/rya_py_2026.csv — do not edit by hand; re-run script.
-- https://www.rya.org.uk — data © Royal Yachting Association (use per your licence).

alter table public.rya_class_py
  add column if not exists category text,
  add column if not exists crew_count smallint,
  add column if not exists rig text,
  add column if not exists spinnaker text,
  add column if not exists keel text,
  add column if not exists engine text;

comment on column public.rya_class_py.display_name is 'RYA Type (class name as published).';
comment on column public.rya_class_py.py is 'RYA Portsmouth Yardstick handicap.';
comment on column public.rya_class_py.category is 'RYA Category (e.g. Dinghy, Keelboat).';
comment on column public.rya_class_py.crew_count is 'RYA No of crew.';
comment on column public.rya_class_py.rig is 'RYA Rig.';
comment on column public.rya_class_py.spinnaker is 'RYA Spinnaker.';
comment on column public.rya_class_py.keel is 'RYA Keel.';
comment on column public.rya_class_py.engine is 'RYA Engine (when provided in source data).';

comment on table public.rya_class_py is 'System Portsmouth handicaps keyed by normalized class name; seeded from repo data CSV (Royal Yachting Association).';

alter table public.rya_class_py
  add constraint rya_class_py_crew_count_check
  check (crew_count is null or (crew_count >= 1 and crew_count <= 20))
  not valid;

alter table public.rya_class_py validate constraint rya_class_py_crew_count_check;

on conflict (class_key) do update set
  display_name = excluded.display_name,
  py = excluded.py,
  category = excluded.category,
  crew_count = excluded.crew_count,
  rig = excluded.rig,
  spinnaker = excluded.spinnaker,
  keel = excluded.keel,
  engine = excluded.engine;
